import React, { Component } from 'react';
import Home from './pages/Home';
import About from './pages/About';
import ProjectPage from './pages/ProjectPage';
import Test from './pages/Test';
import { BrowserRouter as Router, Route, Switch } from 'react-router-dom';
import './App.css';
import './components/work-grid.css';
import './components/sidebar.css';
import './components/responsive.css';
import 'bootstrap/dist/css/bootstrap.css';

class App extends Component {
  state = {
    projects: [
      {
        id: 1,
        name: 'Booklandia',
        desc: 'Website',
        img: 'img/works/booklandia-site.png',
        url: '',
      },
      {
        id: 2,
        name: 'TESDA Womens Center',
        desc: 'Website',
        img: 'img/works/twc.png',
      },
      {
        id: 3,
        name: 'Romblon Institute of Technology',
        desc: 'Website',
        img: 'img/works/fun-run.png',
      },
      {
        id: 4,
        name: 'Finest Aluminum Catalogue',
        desc: 'Design',
        img: 'img/works/finest-catalogue.png',
      },
      {
        id: 5,
        name: 'Finest Aluminum Brochure',
        desc: 'Design',
        img: 'img/works/finest-brochure.png',
      },
      {
        id: 6,
        name: 'P&G Events',
        desc: 'Design',
        img: 'img/works/PandG.png',
      },
      {
        id: 7,
        name: 'DEPED K12 Infographics',
        desc: 'Design',
        img: 'img/works/k12.png',
      },
      {
        id: 8,
        name: 'Famrun 2018',
        desc: 'Design',
        img: 'img/works/fun-run.png',
      },
    ],
  };
  render() {
    return (
      <div className="global-outer">
        <div className="global-inner">
          <Router>
              <Switch>
                <Route exact path='/' component={Home} />
                <Route path='/about' component={About} />
                <Route path='/project/:id' component={ProjectPage} />
                <Test  projects={this.state.projects} />
              </Switch>

          </Router>
        </div>
      </div>
    );
  }
}



export default App;
